import pymysql
import functions_framework
from urllib.parse import unquote
import os

@functions_framework.http
def search_api(request):
    # Enable secure environment variables
    db_config = {
        'host': os.environ.get('DB_HOST'),
        'user': os.environ.get('DB_USER'),
        'password': os.environ.get('DB_PASSWORD'),
        'database': os.environ.get('DB_NAME'),
        'charset': 'utf8mb4'
    }
    
    # Initialize connection
    connection = None
    try:
        connection = pymysql.connect(**db_config)
        cursor = connection.cursor(pymysql.cursors.DictCursor)
        
        # Build dynamic query from request parameters
        base_query = "SELECT * FROM products WHERE 1=1"
        params = []
        
        # Process each parameter safely
        for key, value in request.args.items():
            if key in ['name', 'category', 'brand']:
                # Sanitize input to prevent SQL injection
                safe_value = unquote(str(value))
                if safe_value:
                    base_query += f" AND {key} LIKE %s"
                    params.append(f"%{safe_value}%")
        
        # Handle price range filtering
        min_price = request.args.get('min_price')
        max_price = request.args.get('max_price')
        
        if min_price:
            base_query += " AND price >= %s"
            params.append(float(min_price))
            
        if max_price:
            base_query += " AND price <= %s"
            params.append(float(max_price))
        
        # Handle sorting
        sort_by = request.args.get('sort_by', 'id')
        sort_order = request.args.get('sort_order', 'ASC')
        
        if sort_by in ['id', 'name', 'price', 'category']:
            base_query += f" ORDER BY {sort_by} {sort_order}"
        
        # Handle pagination
        page = int(request.args.get('page', 1))
        per_page = int(request.args.get('per_page', 10))
        offset = (page - 1) * per_page
        base_query += " LIMIT %s OFFSET %s"
        params.append(per_page)
        params.append(offset)
        
        # Execute query
        cursor.execute(base_query, params)
        results = cursor.fetchall()
        
        return {
            'status': 'success',
            'data': results,
            'page': page,
            'per_page': per_page,
            'total': len(results)
        }
        
    except Exception as e:
        return {
            'status': 'error',
            'message': str(e)
        }
    finally:
        if connection:
            connection.close()